#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,y,c;
    long long f;
}a[100010];
bool cmpx(node a,node b)
{
    return a.x<b.x||(a.x==b.x&&a.y<b.y);
}
bool cmpy(node a,node b)
{
    return a.y<b.y;
}
long long ans;
int n,m,k;
void cdq(int l,int r)
{
    if(l>=r)
    {
        return;
    }
    int mid=(l+r)>>1;
    cdq(l,mid);
    sort(a+l,a+mid+1,cmpy);
    sort(a+mid+1,a+r+1,cmpy);
    long long max1=0;
    for(int i=l,j=mid+1;j<=r;j++)
    {
        while(i<=mid&&a[i].y<=a[j].y)
        {
            max1=max(max1,a[i].c+a[i].f);
            i++;
        }
        a[j].f=max(a[j].f,max1);
    }
    sort(a+l,a+mid+1,cmpx);
    sort(a+mid+1,a+r+1,cmpx);
    cdq(mid+1,r);
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=k;i++)
    {
        scanf("%d%d%d",&a[i].x,&a[i].y,&a[i].c);
    }
    sort(a+1,a+1+k,cmpx);
    cdq(1,k);
    for(int i=1;i<=k;i++)
    {
        ans=max(ans,a[i].f+a[i].c);
    }
    printf("%lld",ans);
    return 0;
}
